import { useEffect, useRef, useState } from 'react';
import { Link } from 'react-router-dom';
import { ArrowRight, Check, Globe, Gamepad2, Palette, Monitor, Smartphone, Chrome, Tv2, ChevronDown } from 'lucide-react';

const SVCS = [
  {
    id: 'fullstack', Icon: Globe,
    title: 'Full Stack Web Development',
    tagline: 'Enterprise-grade web apps, built end-to-end.',
    color: '#0057ff',
    img: 'https://images.unsplash.com/photo-1498050108023-c5249f4df085?w=1400&q=85',
    overview: 'We build complete web applications from the ground up — modern responsive frontends paired with powerful, secure, and scalable backends.',
    included: [
      'Frontend: React.js, Next.js, Vue.js, Tailwind CSS',
      'Backend: Node.js, Python (Django/FastAPI), REST & GraphQL APIs',
      'Database: PostgreSQL, MongoDB, MySQL, Firebase',
      'Cloud & DevOps: AWS, Azure, Docker, Kubernetes, CI/CD',
      'E-commerce platforms, SaaS products, enterprise portals',
      'Performance audits and legacy system modernisation',
    ],
    process: [
      { s: 'Discovery',          d: 'Define goals, tech requirements and roadmap' },
      { s: 'Design & Architecture', d: 'System design and UI/UX wireframing' },
      { s: 'Development',        d: 'Agile sprints with regular client updates' },
      { s: 'QA & Testing',       d: 'Functional, performance and security testing' },
      { s: 'Deployment',         d: 'Cloud deployment with automated pipelines' },
      { s: 'Support',            d: 'Ongoing maintenance and optimisation' },
    ],
  },
  {
    id: 'gamedev', Icon: Gamepad2,
    title: 'Game Development',
    tagline: 'From mobile hits to immersive 3D worlds.',
    color: '#7c3aed',
    img: 'https://images.unsplash.com/photo-1616588589676-62b3bd4ff6d2?w=1400&q=85',
    overview: 'From hypercasual mobile titles to complex 3D multiplayer environments, we bring interactive visions to life with technical precision and creative flair.',
    included: [
      '2D and 3D game development (Unity, Unreal Engine)',
      'Mobile game development for iOS & Android',
      'Multiplayer and networked game systems',
      'Game UI/UX design, HUD design and asset integration',
      'Gameplay mechanics, physics systems, AI behaviour',
      'Prototyping, playtesting and post-launch live-ops',
    ],
    platforms: [
      { Icon: Smartphone, l: 'Mobile (iOS/Android)' },
      { Icon: Monitor,    l: 'PC (Windows/macOS)'   },
      { Icon: Chrome,     l: 'WebGL (browser)'       },
      { Icon: Tv2,        l: 'Console (scoped)'      },
    ],
  },
  {
    id: 'uiux', Icon: Palette,
    title: 'UI/UX Design & Consulting',
    tagline: 'Interfaces users love. Products that convert.',
    color: '#db2777',
    img: 'https://images.unsplash.com/photo-1561070791-2526d30994b5?w=1400&q=85',
    overview: 'Outstanding technology deserves outstanding design. We create interfaces that users love — intuitive, accessible, and visually refined.',
    included: [
      'User research, persona development and journey mapping',
      'Wireframing, prototyping and usability testing',
      'Design systems and component libraries (Figma)',
      'Responsive and ADA-compliant interface design',
      'Technology stack advisory and architecture consulting',
      'Code reviews, technical audits and performance assessments',
    ],
  },
];

/* ── Parallax image panel ── */
function ParallaxService({ svc, index }) {
  const sectionRef = useRef(null);
  const imgRef     = useRef(null);
  const contentRef = useRef(null);
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    // Intersection observer — fade-in content when section enters view
    const io = new IntersectionObserver(
      ([entry]) => { if (entry.isIntersecting) setVisible(true); },
      { threshold: 0.15 }
    );
    if (sectionRef.current) io.observe(sectionRef.current);

    // Scroll parallax on image
    const onScroll = () => {
      if (!sectionRef.current || !imgRef.current) return;
      const rect = sectionRef.current.getBoundingClientRect();
      const progress = -rect.top / (rect.height || 1);
      const shift = progress * 60; // px shift — subtle
      imgRef.current.style.transform = `translateY(${shift}px) scale(1.12)`;
    };
    window.addEventListener('scroll', onScroll, { passive: true });
    onScroll();
    return () => { io.disconnect(); window.removeEventListener('scroll', onScroll); };
  }, []);

  const isEven = index % 2 === 0;

  return (
    <section
      ref={sectionRef}
      id={svc.id}
      style={{
        display: 'grid',
        gridTemplateColumns: '1fr',
        minHeight: '88vh',
        borderTop: '1px solid var(--rule)',
        overflow: 'hidden',
        background: isEven ? 'var(--white)' : '#f5f7ff',
      }}
      className="svc-section"
    >
      {/* Image side */}
      <div style={{
        position: 'relative', overflow: 'hidden',
        minHeight: 300,
        order: isEven ? 2 : 1,
      }} className="svc-img-col">
        <img
          ref={imgRef}
          src={svc.img}
          alt={svc.title}
          style={{
            position: 'absolute', inset: '-10% 0',
            width: '100%', height: '120%',
            objectFit: 'cover',
            willChange: 'transform',
            transition: 'transform 0.05s linear',
            transform: 'translateY(0) scale(1.12)',
          }}
        />
        {/* Colour tint overlay */}
        <div style={{
          position: 'absolute', inset: 0,
          background: `linear-gradient(135deg, ${svc.color}22 0%, transparent 60%)`,
        }}/>
        {/* Number watermark */}
        <div style={{
          position: 'absolute', bottom: -20, right: -10,
          fontFamily: 'var(--serif)', fontSize: 'clamp(6rem,14vw,11rem)',
          fontWeight: 900, color: 'rgba(255,255,255,0.07)',
          lineHeight: 1, pointerEvents: 'none', userSelect: 'none',
        }}>
          {String(index + 1).padStart(2, '0')}
        </div>
        {/* Icon badge */}
        <div style={{
          position: 'absolute', top: 28, left: 28,
          width: 52, height: 52, borderRadius: 14,
          background: 'rgba(255,255,255,0.15)',
          backdropFilter: 'blur(12px)',
          border: '1px solid rgba(255,255,255,0.3)',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          color: '#fff',
        }}>
          <svc.Icon size={22} />
        </div>
      </div>

      {/* Content side */}
      <div
        ref={contentRef}
        style={{
          padding: 'clamp(40px,6vw,72px) clamp(24px,5vw,64px)',
          display: 'flex', flexDirection: 'column', justifyContent: 'center',
          order: isEven ? 1 : 2,
          opacity: visible ? 1 : 0,
          transform: visible ? 'translateX(0)' : `translateX(${isEven ? '-40px' : '40px'})`,
          transition: 'opacity 0.7s ease, transform 0.7s ease',
        }}
      >
        {/* Tag */}
        <div style={{
          display: 'inline-flex', alignItems: 'center', gap: 8,
          marginBottom: 20,
        }}>
          <div style={{ width: 28, height: 3, borderRadius: 2, background: svc.color }} />
          <span style={{
            fontSize: '0.7rem', fontWeight: 700, letterSpacing: '0.16em',
            textTransform: 'uppercase', color: svc.color,
          }}>Service {String(index + 1).padStart(2, '0')}</span>
        </div>

        <h2 style={{
          fontFamily: 'var(--serif)',
          fontSize: 'clamp(1.7rem,3.5vw,2.8rem)',
          fontWeight: 800, lineHeight: 1.12,
          color: 'var(--ink)', marginBottom: 10,
          letterSpacing: '-0.02em',
        }}>{svc.title}</h2>

        <p style={{
          fontSize: '0.88rem', fontWeight: 600,
          color: svc.color, marginBottom: 20,
          letterSpacing: '0.02em',
        }}>{svc.tagline}</p>

        <p style={{
          fontSize: '0.95rem', color: 'var(--ink60)',
          lineHeight: 1.8, marginBottom: 28, maxWidth: 480,
        }}>{svc.overview}</p>

        {/* Included list */}
        <div style={{ marginBottom: 28 }}>
          <h4 style={{
            fontSize: '0.65rem', fontWeight: 700, letterSpacing: '0.16em',
            textTransform: 'uppercase', color: 'var(--ink20)',
            marginBottom: 14,
          }}>What's Included</h4>
          <ul style={{ listStyle: 'none', padding: 0, display: 'flex', flexDirection: 'column', gap: 9 }}>
            {svc.included.map((item, i) => (
              <li key={i} style={{ display: 'flex', alignItems: 'flex-start', gap: 10 }}>
                <span style={{
                  width: 18, height: 18, borderRadius: 5, flexShrink: 0, marginTop: 1,
                  background: `${svc.color}18`, border: `1px solid ${svc.color}33`,
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                }}>
                  <Check size={10} style={{ color: svc.color }} />
                </span>
                <span style={{ fontSize: '0.88rem', color: 'var(--ink60)', lineHeight: 1.65 }}>{item}</span>
              </li>
            ))}
          </ul>
        </div>

        {/* Process timeline (fullstack only) */}
        {svc.process && (
          <div style={{ marginBottom: 28 }}>
            <h4 style={{ fontSize: '0.65rem', fontWeight: 700, letterSpacing: '0.16em', textTransform: 'uppercase', color: 'var(--ink20)', marginBottom: 14 }}>Our Process</h4>
            <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
              {svc.process.map((step, i) => (
                <div key={i} style={{ display: 'flex', alignItems: 'center', gap: 7 }}>
                  <div style={{
                    padding: '5px 12px', borderRadius: 999,
                    background: `${svc.color}12`, border: `1px solid ${svc.color}28`,
                    fontSize: '0.78rem', fontWeight: 600, color: svc.color,
                  }}>
                    {String(i + 1).padStart(2, '0')} {step.s}
                  </div>
                  {i < svc.process.length - 1 && (
                    <span style={{ color: 'var(--ink-10)', fontSize: '0.7rem' }}>›</span>
                  )}
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Platforms (gamedev only) */}
        {svc.platforms && (
          <div style={{ marginBottom: 28 }}>
            <h4 style={{ fontSize: '0.65rem', fontWeight: 700, letterSpacing: '0.16em', textTransform: 'uppercase', color: 'var(--ink20)', marginBottom: 14 }}>Platforms</h4>
            <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
              {svc.platforms.map(({ Icon, l }) => (
                <div key={l} style={{
                  display: 'flex', alignItems: 'center', gap: 7,
                  padding: '7px 14px', borderRadius: 999,
                  background: `${svc.color}0e`, border: `1px solid ${svc.color}25`,
                }}>
                  <Icon size={13} style={{ color: svc.color }} />
                  <span style={{ fontSize: '0.8rem', fontWeight: 500, color: 'var(--ink60)' }}>{l}</span>
                </div>
              ))}
            </div>
          </div>
        )}

        <Link to="/contact" style={{
          display: 'inline-flex', alignItems: 'center', gap: 8,
          padding: '11px 22px', borderRadius: 10,
          background: svc.color, color: '#fff',
          fontSize: '0.85rem', fontWeight: 700,
          transition: 'all 0.2s', alignSelf: 'flex-start',
          boxShadow: `0 4px 18px ${svc.color}40`,
        }}
          onMouseEnter={e => { e.currentTarget.style.transform = 'translateY(-2px)'; e.currentTarget.style.boxShadow = `0 8px 24px ${svc.color}55`; }}
          onMouseLeave={e => { e.currentTarget.style.transform = 'translateY(0)'; e.currentTarget.style.boxShadow = `0 4px 18px ${svc.color}40`; }}
        >
          Start this project <ArrowRight size={14} />
        </Link>
      </div>
    </section>
  );
}

export default function Services() {
  return (
    <div>
      {/* HERO */}
      <section style={{
        position: 'relative', minHeight: '60vh',
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        background: '#040b18', overflow: 'hidden', textAlign: 'center',
      }}>
        <img src="https://images.unsplash.com/photo-1521737604893-d14cc237f11d?w=1800&q=75"
          alt="" aria-hidden style={{ position: 'absolute', inset: 0, width: '100%', height: '100%', objectFit: 'cover', opacity: .12 }} />
        <div style={{ position: 'absolute', inset: 0, background: 'linear-gradient(160deg,rgba(4,11,24,0.97) 0%,rgba(0,30,90,0.82) 60%,rgba(4,11,24,0.97) 100%)' }} />
        <div style={{ position: 'absolute', top: '40%', left: '50%', transform: 'translate(-50%,-50%)', width: 500, height: 500, background: 'radial-gradient(circle,rgba(0,87,255,0.1) 0%,transparent 70%)', pointerEvents: 'none' }} />

        <div className="wrap" style={{ position: 'relative', zIndex: 1, padding: '130px 20px 80px' }}>
          <span style={{ fontSize: '0.7rem', fontWeight: 700, letterSpacing: '0.18em', textTransform: 'uppercase', color: 'rgba(255,255,255,0.4)', display: 'block', marginBottom: 16 }}>Our Services</span>
          <h1 style={{ fontFamily: 'var(--serif)', fontSize: 'clamp(2.2rem,6vw,4.5rem)', fontWeight: 800, color: '#fff', lineHeight: 1.08, letterSpacing: '-0.025em', marginBottom: 20 }}>
            Enterprise-Grade Dev.<br />
            <em style={{ fontStyle: 'italic', color: '#5aa8ff' }}>Startup Speed.</em>
          </h1>
          <p style={{ fontSize: 'clamp(0.9rem,1.6vw,1.05rem)', color: 'rgba(255,255,255,0.58)', maxWidth: 460, margin: '0 auto 40px', lineHeight: 1.8 }}>
            From web platforms to playable worlds — scalable, robust, and built to last.
          </p>
          {/* Scroll prompt */}
          <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 6, opacity: 0.45 }}>
            <span style={{ fontSize: '0.65rem', color: '#fff', letterSpacing: '0.14em', textTransform: 'uppercase' }}>Scroll to explore</span>
            <ChevronDown size={16} color="#fff" style={{ animation: 'bounce 1.6s ease-in-out infinite' }} />
          </div>
        </div>
      </section>

      {/* SERVICE PANELS */}
      {SVCS.map((svc, idx) => (
        <ParallaxService key={svc.id} svc={svc} index={idx} />
      ))}

      {/* CTA */}
      <section style={{ background: '#060c18', position: 'relative', overflow: 'hidden' }}>
        <img src="https://images.unsplash.com/photo-1551434678-e076c223a692?w=1600&q=75"
          alt="" aria-hidden style={{ position: 'absolute', inset: 0, width: '100%', height: '100%', objectFit: 'cover', opacity: .07 }} />
        <div style={{ position: 'absolute', inset: 0, background: 'rgba(6,12,24,0.96)' }} />
        <div className="wrap" style={{ padding: '80px 20px', position: 'relative', zIndex: 1, textAlign: 'center' }}>
          <span style={{ fontSize: '0.68rem', fontWeight: 700, letterSpacing: '0.18em', textTransform: 'uppercase', color: 'rgba(255,255,255,0.35)', display: 'block', marginBottom: 16 }}>Ready to Build?</span>
          <h2 style={{ fontFamily: 'var(--serif)', fontSize: 'clamp(1.8rem,4vw,3rem)', fontWeight: 800, color: '#fff', marginBottom: 14, letterSpacing: '-0.02em' }}>Have a Project in Mind?</h2>
          <p style={{ fontSize: '0.95rem', color: 'rgba(255,255,255,0.5)', lineHeight: 1.8, maxWidth: 460, margin: '0 auto 32px' }}>
            Tell us about your idea and we'll build a tailored plan to bring it to life — on time, within budget, and beyond expectations.
          </p>
          <Link to="/contact" style={{
            display: 'inline-flex', alignItems: 'center', gap: 8,
            padding: '14px 30px', borderRadius: 10,
            background: '#fff', color: 'var(--ink)',
            fontSize: '0.9rem', fontWeight: 700,
            transition: 'all 0.2s', boxShadow: '0 4px 20px rgba(255,255,255,0.15)',
          }}
            onMouseEnter={e => { e.currentTarget.style.background = '#0057ff'; e.currentTarget.style.color = '#fff'; }}
            onMouseLeave={e => { e.currentTarget.style.background = '#fff'; e.currentTarget.style.color = 'var(--ink)'; }}
          >
            Get a Free Consultation <ArrowRight size={15} />
          </Link>
        </div>
      </section>

      <style>{`
        /* 2-col split on desktop */
        @media (min-width: 768px) {
          .svc-section { grid-template-columns: 1fr 1fr !important; min-height: 88vh !important; }
          .svc-img-col { min-height: unset !important; }
        }
        @media (max-width: 767px) {
          .svc-img-col { min-height: 260px !important; order: 1 !important; }
          .svc-section > div:last-child { order: 2 !important; }
        }
        @keyframes bounce {
          0%,100% { transform: translateY(0); }
          50%      { transform: translateY(6px); }
        }
      `}</style>
    </div>
  );
}
